#include <stdio.h>
#include <stdlib.h>

typedef struct {int s; int e;} Interval;
int cmpInterval(const void *a, const void *b) {
    const Interval *ia = (const Interval*)a;
    const Interval *ib = (const Interval*)b;
    return ia->s - ib->s;
}
int cmpInt(const void *a, const void *b) {
    return (*(int*)a) - (*(int*)b);
}

int main() {
    int T; if (scanf("%d", &T)!=1) return 0;
    while (T--) {
        int N; scanf("%d", &N);
        Interval *arr = (Interval*)malloc(sizeof(Interval)*N);
        for (int i=0;i<N;i++) scanf("%d %d", &arr[i].s, &arr[i].e);
        qsort(arr, N, sizeof(Interval), cmpInterval);
        int Q; scanf("%d", &Q);
        while (Q--) {
            int K; scanf("%d", &K);
            int *times = (int*)malloc(sizeof(int)*K);
            for (int i=0;i<K;i++) scanf("%d", &times[i]);
            qsort(times, K, sizeof(int), cmpInt);
            long long ans = 0;
            int ptr = 0;
            for (int i=0;i<N;i++) {
                while (ptr < K && times[ptr] < arr[i].s) ptr++;
                if (ptr < K && times[ptr] < arr[i].e) ans++;
            }
            printf("%lld\n", ans);
            free(times);
        }
        free(arr);
    }
    return 0;
}

