import java.io.*;
import java.util.*;

public class Main {
    private static class Interval {
        int s, e;
        Interval(int s, int e) { this.s = s; this.e = e; }
    }
    public static void main(String[] args) throws Exception {
        FastScanner fs = new FastScanner(System.in);
        int T = fs.nextInt();
        StringBuilder out = new StringBuilder();
        while (T-- > 0) {
            int N = fs.nextInt();
            Interval[] rec = new Interval[N];
            for (int i = 0; i < N; i++) rec[i] = new Interval(fs.nextInt(), fs.nextInt());
            Arrays.sort(rec, Comparator.comparingInt(a -> a.s));
            int Q = fs.nextInt();
            while (Q-- > 0) {
                int K = fs.nextInt();
                int[] t = new int[K];
                for (int i = 0; i < K; i++) t[i] = fs.nextInt();
                Arrays.sort(t);
                long ans = 0;
                int ptr = 0;
                for (Interval in : rec) {
                    while (ptr < K && t[ptr] < in.s) ptr++;
                    if (ptr < K && t[ptr] < in.e) ans++;
                }
                out.append(ans).append('\n');
            }
        }
        System.out.print(out.toString());
    }
    // Fast scanner for large input
    private static class FastScanner {
        private final InputStream in;
        private final byte[] buffer = new byte[1 << 16];
        private int ptr = 0, len = 0;
        FastScanner(InputStream in) { this.in = in; }
        private int readByte() throws IOException {
            if (ptr >= len) {
                len = in.read(buffer);
                ptr = 0;
                if (len <= 0) return -1;
            }
            return buffer[ptr++];
        }
        int nextInt() throws IOException {
            int c, sign = 1, val = 0;
            do { c = readByte(); } while (c <= ' ');
            if (c == '-') { sign = -1; c = readByte(); }
            while (c > ' ') {
                val = val * 10 + (c - '0');
                c = readByte();
            }
            return val * sign;
        }
    }
}

