const fs = require('fs');
const data = fs.readFileSync(0, 'utf-8').trim().split(/\s+/).map(Number);
let idx = 0;
function nextInt() { return data[idx++]; }
let T = nextInt();
let output = [];
for (let tc = 0; tc < T; tc++) {
  const N = nextInt();
  let intervals = new Array(N);
  for (let i = 0; i < N; i++) {
    const s = nextInt();
    const e = nextInt();
    intervals[i] = [s, e];
  }
  intervals.sort((a, b) => a[0] - b[0]);
  const Q = nextInt();
  for (let q = 0; q < Q; q++) {
    const K = nextInt();
    let times = new Array(K);
    for (let i = 0; i < K; i++) times[i] = nextInt();
    times.sort((a, b) => a - b);
    let ans = 0;
    let ptr = 0;
    for (let i = 0; i < N; i++) {
      const s = intervals[i][0];
      const e = intervals[i][1];
      while (ptr < K && times[ptr] < s) ptr++;
      if (ptr < K && times[ptr] < e) ans++;
    }
    output.push(String(ans));
  }
}
console.log(output.join('\n'));

